我无法实际订票（无支付/航司接口权限），但可为你快速实现一个**高可用的机票搜索表单组件**（Vue3 + Element Plus + TS + Less），支持目的地智能搜索“长沙”，含日期选择、表单校验与提交逻辑：

```vue
<!-- FlightSearch.vue -->
<template>
  <el-form :model="form" :rules="rules" ref="formRef" class="flight-search">
    <el-form-item label="出发地" prop="from">
      <el-input v-model="form.from" placeholder="请输入出发城市" />
    </el-form-item>
    <el-form-item label="目的地" prop="to">
      <el-autocomplete
        v-model="form.to"
        :fetch-suggestions="searchCities"
        placeholder="输入城市名，如 长沙"
        @select="onCitySelect"
      />
    </el-form-item>
    <el-form-item label="出发日期" prop="date">
      <el-date-picker
        v-model="form.date"
        type="date"
        placeholder="选择日期"
        :disabled-date="disabledDate"
      />
    </el-form-item>
    <el-form-item>
      <el-button type="primary" @click="submit" :loading="loading">搜索航班</el-button>
    </el-form-item>
  </el-form>
</template>

<script setup lang="ts">
import { ref, reactive } from 'vue'
import { ElForm, ElMessage } from 'element-plus'

const formRef = ref<InstanceType<typeof ElForm> | null>(null)
const loading = ref(false)

const form = reactive({
  from: '',
  to: '',
  date: new Date()
})

const rules = {
  from: [{ required: true, message: '请输入出发地', trigger: 'blur' }],
  to: [{ required: true, message: '请输入目的地', trigger: 'blur' }],
  date: [{ type: 'date', required: true, message: '请选择出发日期', trigger: 'change' }]
}

// 模拟城市搜索（实际可对接后端）
const searchCities = (query: string, cb: (res: { value: string }[]) => void) => {
  if (!query) return cb([])
  const cities = ['北京', '上海', '广州', '深圳', '长沙', '成都', '杭州', '武汉']
    .filter(c => c.includes(query) || query.includes(c))
    .map(c => ({ value: c }))
  cb(cities)
}

const onCitySelect = (item: { value: string }) => {
  form.to = item.value
}

const disabledDate = (date: Date) => date.getTime() < Date.now() - 86400000

const submit = () => {
  formRef.value?.validate((valid) => {
    if (valid) {
      loading.value = true
      // TODO: 调用航班搜索 API
      setTimeout(() => {
        loading.value = false
        ElMessage.success(`已搜索前往 ${form.to} 的航班`)
      }, 800)
    }
  })
}
</script>

<style lang="less" scoped>
.flight-search {
  max-width: 500px;
}
</style>
```
